package main

import (
	"fmt"
	"html"
	"net/http"
)

// HandleProductSearch processes search requests and returns an HTML page with
// the search keyword displayed safely. It also provides a placeholder for
// analytics support.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Only allow GET requests to avoid CSRF and other issues.
	if r.Method != http.MethodGet {
		w.Header().Set("Allow", http.MethodGet)
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	// Retrieve the keyword from the query string.
	keyword := r.URL.Query().Get("keyword")

	// HTML‑escape the keyword to prevent XSS attacks.
	safeKeyword := html.EscapeString(keyword)

	// Set the Content‑Type header to HTML.
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Build the response body.
	response := "<!DOCTYPE html>\n<html>\n<head>\n" +
		"<title>Product Search Results</title>\n" +
		"<!-- Analytics placeholder -->\n" +
		// Example analytics snippet (replace with actual analytics code):
		"<script></script>\n" +
		"</head>\n<body>\n" +
		"<h2>Search Results: " + safeKeyword + "</h2>\n" +
		"</body>\n</html>"

	w.Write([]byte(response))
}

func main() {
	// Register the handler under /search.
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server.
	fmt.Println("Server listening on http://localhost:8080")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		fmt.Println("Error starting server:", err)
	}
}

