package main

import (
	"html"
	"net/http"
	"strconv"
)

// HandleProductSearch responds with an HTML page showing the search results
// for the keyword passed in the "keyword" query parameter. It also includes
// a simple analytics script that logs a page‑view event.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Set the response content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Retrieve the keyword from the query string
	keyword := r.URL.Query().Get("keyword")

	// Escape the keyword for safe insertion into HTML
	safeKeyword := html.EscapeString(keyword)

	// Quote the keyword for safe insertion into a JavaScript string
	jsKeyword := strconv.Quote(safeKeyword)

	// Build the HTML page with analytics script
	htmlContent := `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Search Results</title>
    <script>
    (function() {
        // Simple analytics data structure
        var analyticsData = {
            event: "page_view",
            page: "search",
            keyword: ` + jsKeyword + `
        };
        // In a production environment you would send this data to your analytics service.
        console.log("Analytics:", JSON.stringify(analyticsData));
        // Example: fetch('/analytics', {method: 'POST', body: JSON.stringify(analyticsData)});
    })();
    </script>
</head>
<body>
    <h2>Search Results: ` + safeKeyword + `</h2>
    <p>Below are the search results for your query:</p>
    <ul>
        <li>Product A</li>
        <li>Product B</li>
        <li>Product C</li>
    </ul>
</body>
</html>`

	// Write the HTML response
	w.Write([]byte(htmlContent))
}

func main() {
	// Register the search handler at the /search endpoint
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server on port 8080
	http.ListenAndServe(":8080", nil)
}

