package main

import (
	"html"
	"net/http"
	"net/url"
	"strings"
)

// HandleProductSearch processes product search requests.
// It reads the "keyword" query parameter, escapes it for safe HTML display,
// and includes a simple analytics tracking pixel.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Retrieve the search keyword from the URL query string
	keyword := r.URL.Query().Get("keyword")

	// Escape the keyword to prevent XSS when rendering in HTML
	safeKeyword := html.EscapeString(keyword)

	// URL‑encode the keyword for use in the analytics pixel's query string
	encodedKeyword := url.QueryEscape(keyword)

	// Set the response Content-Type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Build the HTML response using a strings.Builder for efficiency
	var sb strings.Builder
	sb.WriteString("<!DOCTYPE html>\n")
	sb.WriteString("<html>\n")
	sb.WriteString("<head>\n")
	sb.WriteString("    <title>Product Search Results</title>\n")
	sb.WriteString("</head>\n")
	sb.WriteString("<body>\n")
	// Display the keyword in the required heading format
	sb.WriteString("<h2>Search Results: " + safeKeyword + "</h2>\n")
	// Include a 1x1 pixel that forwards the keyword to an analytics endpoint
	sb.WriteString(`<img src="/analytics?type=search&keyword=` + encodedKeyword + `" width="1" height="1" style="display:none;">` + "\n")
	sb.WriteString("</body>\n")
	sb.WriteString("</html>")

	// Write the complete HTML response to the client
	w.Write([]byte(sb.String()))
}

// main registers the handler and starts the HTTP server (for demonstration).
func main() {
	// Register the product search handler at the /search endpoint
	http.HandleFunc("/search", HandleProductSearch)

	// In a real application you would implement the /analytics endpoint
	// to collect the data sent by the tracking pixel.

	// Start the HTTP server on port 8080
	http.ListenAndServe(":8080", nil)
}

