package main

import (
	"html"
	"net/http"
)

func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Restrict to GET requests to follow proper semantics (optional but recommended)
	if r.Method != http.MethodGet {
		w.WriteHeader(http.StatusMethodNotAllowed)
		return
	}

	// Retrieve the keyword from the query string
	keyword := r.URL.Query().Get("keyword")

	// Escape the keyword to prevent Cross‑Site Scripting (XSS)
	safeKeyword := html.EscapeString(keyword)

	// Set the appropriate Content-Type for HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Build the HTML response
	html := "<!DOCTYPE html>\n<html>\n<head>\n<title>Product Search Results</title>\n</head>\n<body>\n" +
		"<h2>Search Results: " + safeKeyword + "</h2>\n" +
		"</body>\n</html>"

	w.Write([]byte(html))
}

func main() {
	// Register the handler for the /search endpoint
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server (listening on port 8080)
	http.ListenAndServe(":8080", nil)
}

