package main

import (
	"fmt"
	"html"
	"log"
	"net/http"
	"strings"
)

// HandleProductSearch processes search requests.
// It expects a query parameter "keyword". The keyword is displayed
// in the response as <h2>Search Results: <keyword></h2>.
// It also includes a simple analytics placeholder.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Only allow GET requests
	if r.Method != http.MethodGet {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	// Extract the keyword from query parameters.
	// If multiple values are given, use the first one.
	keys := r.URL.Query()["keyword"]
	var keyword string
	if len(keys) > 0 {
		keyword = keys[0]
	}

	// Sanitize the keyword to prevent XSS
	keyword = html.EscapeString(keyword)

	// Simple analytics: log the search request
	log.Printf("Search request: keyword=%q", keyword)

	// Set response content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Build the HTML response using a strings.Builder
	var sb strings.Builder

	// Basic HTML page with analytics placeholder
	sb.WriteString(`<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Product Search</title>
    <!-- Placeholder for analytics (e.g., Google Analytics) -->
    <script>
        (function() {
            // Replace the ID below with a real analytics tracking ID
            var analyticsID = "UA-XXXXX-Y";
            console.log("Analytics ID loaded:", analyticsID);
            // Example: track a page view for this search
            console.log("Search page viewed, keyword: ` + keyword + `");
        })();
    </script>
</head>
<body>
    <h2>Search Results: ` + keyword + `</h2>
    <p>Search results for the keyword will appear here.</p>
    <!-- Example product list placeholder -->
    <ul>
        <li>Product A</li>
        <li>Product B</li>
        <li>Product C</li>
    </ul>
</body>
</html>`)

	// Write the HTML response to the client
	fmt.Fprint(w, sb.String())
}

func main() {
	// Register the search handler and start the HTTP server
	http.HandleFunc("/", HandleProductSearch)

	log.Println("Server starting on http://localhost:8080")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatalf("ListenAndServe error: %v", err)
	}
}

