package main

import (
	"encoding/json"
	"html"
	"net/http"
)

// HandleProductSearch processes GET requests containing a "keyword" query
// parameter, renders an HTML page showing the search results, and includes a
// simple client‑side analytics snippet. The keyword is properly escaped to
// prevent XSS attacks.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Only allow GET requests; respond with "Method Not Allowed" otherwise
	if r.Method != http.MethodGet {
		w.Header().Set("Allow", http.MethodGet)
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	// Retrieve the keyword from the query string
	keyword := r.URL.Query().Get("keyword")

	// Escape the keyword for safe inclusion in HTML
	safeKeywordHTML := html.EscapeString(keyword)

	// Marshal the keyword into a JSON string for safe embedding in JavaScript
	jsonKeyword, err := json.Marshal(keyword)
	if err != nil {
		jsonKeyword = []byte("null")
	}

	// Set the Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Build the HTML response, including a basic analytics script.
	// Replace the placeholder script with a real analytics solution (e.g., Google Analytics, Mixpanel, etc.).
	response := `<!DOCTYPE html>
<html>
<head>
<title>Product Search Results</title>
<script>
  // Simple client‑side analytics placeholder.
  // Replace this block with real analytics code.
  (function() {
    var keyword = ` + string(jsonKeyword) + `;
    // Example: push a custom event to the dataLayer (for use with Google Tag Manager, etc.)
    if (window.dataLayer) {
      window.dataLayer.push({
        event: 'search',
        keyword: keyword
      });
    }
    // Example: log the search to the console for debugging
    console.log('Search performed with keyword:', keyword);
  })();
</script>
</head>
<body>
<h2>Search Results: ` + safeKeywordHTML + `</h2>
</body>
</html>`

	w.Write([]byte(response))
}

// main starts an HTTP server on port 8080 and registers HandleProductSearch
// under the /search endpoint.
func main() {
	http.HandleFunc("/search", HandleProductSearch)
	if err := http.ListenAndServe(":8080", nil); err != nil {
		panic(err)
	}
}

