package main

import (
	"encoding/json"
	"fmt"
	"html"
	"net/http"
)

func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Only allow GET method to prevent CSRF and other issues
	if r.Method != http.MethodGet {
		w.Header().Set("Allow", http.MethodGet)
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	// Retrieve the keyword from the query string
	keyword := r.URL.Query().Get("keyword")

	// Escape the keyword for safe inclusion in HTML to mitigate XSS
	safeKeyword := html.EscapeString(keyword)

	// Marshal the keyword into JSON to safely embed it inside a <script> block
	keywordJSON, err := json.Marshal(keyword)
	if err != nil {
		keywordJSON = []byte("null")
	}

	// Build the HTML response with the search results and an analytics script
	response := `<!DOCTYPE html>
<html>
<head>
	<title>Product Search Results</title>
</head>
<body>
	<h2>Search Results: ` + safeKeyword + `</h2>
	<script>
		var keyword = ` + string(keywordJSON) + `;
		// Simple analytics: send a GET request to our analytics endpoint
		(function() {
			var xhr = new XMLHttpRequest();
			xhr.open("GET", "/analytics?event=search&keyword=" + encodeURIComponent(keyword), true);
			xhr.send();
		})();
	</script>
</body>
</html>`

	// Set the Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")
	// Write the HTML response
	w.Write([]byte(response))
}

// HandleAnalytics demonstrates a minimal analytics endpoint.
// In a production environment this would store the event in a database
// or forward it to an external analytics service.
func HandleAnalytics(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodGet {
		w.Header().Set("Allow", http.MethodGet)
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	event := r.URL.Query().Get("event")
	keyword := r.URL.Query().Get("keyword")

	// Log the analytics event (replace with proper logging/metrics in production)
	fmt.Printf("Analytics event: %s, keyword: %s\n", event, keyword)

	// Respond with HTTP 204 No Content
	w.WriteHeader(http.StatusNoContent)
}

func main() {
	// Register handlers
	http.HandleFunc("/search", HandleProductSearch)
	http.HandleFunc("/analytics", HandleAnalytics)

	// Start the HTTP server on port 8080
	fmt.Println("Server starting on :8080")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		fmt.Println("Error starting server:", err)
	}
}

