// HandleProductSearch processes search requests.
// It reads the "keyword" query parameter, escapes it for safety,
// logs the search for analytics, and returns an HTML page with the
// search keyword displayed in an <h2> element.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Set the response content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Retrieve the search keyword from the query string
	keyword := r.URL.Query().Get("keyword")
	// Escape the keyword to prevent XSS attacks
	keyword = html.EscapeString(keyword)

	// Simple analytics: log the search event
	log.Printf("Analytics: search keyword=%q", keyword)

	// Build a minimal HTML page that shows the search results
	html := `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Search Results</title>
</head>
<body>
    <h2>Search Results: ` + keyword + `</h2>
    <p>Here are the product results for your search...</p>
    <!-- Product listing would be rendered here -->
</body>
</html>`

	// Write the HTML response
	w.Write([]byte(html))
}

func main() {
	// Register the handler for the /search endpoint
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server on port 8080
	log.Println("Server listening on http://localhost:8080")
	log.Fatal(http.ListenAndServe(":8080", nil))
}

