import (
	"fmt"
	"html"
	"net/http"
)

// HandleProductSearch processes search requests and returns an HTML page showing the search keyword.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Only allow GET requests
	if r.Method != http.MethodGet {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	// Retrieve the keyword query parameter; if absent, default to empty string
	keyword := r.URL.Query().Get("keyword")
	// Escape the keyword to prevent XSS attacks
	safeKeyword := html.EscapeString(keyword)

	// Set the response Content-Type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Render the HTML page with the search keyword displayed in the title area
	fmt.Fprintf(w, `<!DOCTYPE html>
<html lang="en">
<head>
	<meta charset="UTF-8">
	<meta name="viewport" content="width=device-width, initial-scale=1.0">
	<title>Search Results</title>
	<!-- Analytics placeholder – replace with real analytics script as needed -->
	<script>
		// Example analytics: log the searched keyword to the console
		var searchedKeyword = %q;
		console.log('User searched for:', searchedKeyword);
		// Additional analytics tracking code can be added here
	</script>
</head>
<body>
	<h2>Search Results: %s</h2>
	<!-- Placeholder for product list or further content -->
</body>
</html>`, safeKeyword, safeKeyword)
}

func main() {
	// Register the product search handler at the /search endpoint
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server on port 8080
	fmt.Println("Server running at http://localhost:8080/search")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		fmt.Printf("Server error: %v\n", err)
	}
}

