import (
	"html"
	"net/http"
)

// HandleProductSearch processes search requests and renders an HTML page
// with the user‑supplied keyword. It also includes a placeholder for analytics.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Only allow GET requests; return 405 Method Not Allowed otherwise
	if r.Method != http.MethodGet {
		w.WriteHeader(http.StatusMethodNotAllowed)
		return
	}

	// Retrieve the keyword from the query string
	keyword := r.URL.Query().Get("keyword")

	// Escape the user input to prevent XSS attacks
	safeKeyword := html.EscapeString(keyword)

	// Set the Content‑Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Build the HTML response (including a simple analytics placeholder)
	response := `<!DOCTYPE html>
<html lang="en">
<head>
	<meta charset="UTF-8">
	<title>Product Search Results</title>
	<!-- Analytics support -->
	<script>
		// Example: push search event to an analytics platform (e.g., Google Tag Manager)
		window.dataLayer = window.dataLayer || [];
		window.dataLayer.push({
			'event': 'search',
			'keyword': '` + safeKeyword + `'
		});
	</script>
</head>
<body>
	<h2>Search Results: ` + safeKeyword + `</h2>
</body>
</html>`

	// Write the HTML response to the client
	w.Write([]byte(response))
}

func main() {
	// Register the handler for the /search endpoint
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server (you can change the port if needed)
	http.ListenAndServe(":8080", nil)
}

