package main

import (
	"html"
	"net/http"
)

// HandleProductSearch serves a search results page. It expects a GET request
// with a "keyword" query parameter. The keyword is safely escaped before being
// inserted into the HTML to prevent XSS. An optional analytics script is included
// to log the search term.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Only allow GET requests
	if r.Method != http.MethodGet {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	// Retrieve the keyword from the query string
	keyword := r.URL.Query().Get("keyword")

	// Escape the keyword to protect against XSS attacks
	safeKeyword := html.EscapeString(keyword)

	// Set the Content-Type header to indicate HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Build the HTML response
	// @analytics: The following <script> block can be replaced with real analytics code.
	response := "<!DOCTYPE html>\n<html>\n<head>\n<title>Product Search Results</title>\n"
	response += "<script>\n"
	response += "  // Simple analytics: log the search keyword to the console\n"
	response += "  console.log('Search keyword: " + safeKeyword + "');\n"
	response += "</script>\n"
	response += "</head>\n<body>\n"
	response += "<h2>Search Results: " + safeKeyword + "</h2>\n"
	response += "</body>\n</html>"

	w.Write([]byte(response))
}

// main demonstrates how to register and run the handler.
func main() {
	// Register the product search handler to the /search endpoint
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server on port 8080
	http.ListenAndServe(":8080", nil)
}

