package main

import (
	"encoding/json"
	"fmt"
	"net/http"
	"html"
	"strings"
)

// HandleProductSearch processes product search requests.
// It expects a GET request with a "keyword" query parameter.
// The response is an HTML page showing the search keyword and includes
// a simple analytics script that pushes the keyword to window.dataLayer.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Only allow GET requests; respond with 405 for other methods.
	if r.Method != http.MethodGet {
		w.Header().Set("Allow", http.MethodGet)
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	// Retrieve the keyword from the query string.
	keyword := r.URL.Query().Get("keyword")

	// Escape the keyword to prevent XSS when embedding in HTML.
	escapedKeyword := html.EscapeString(keyword)

	// Prepare a JSON‑safe representation for the analytics script.
	keywordJSON, _ := json.Marshal(escapedKeyword)

	// Set the Content-Type header to HTML.
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Build the HTML response using a strings.Builder for efficiency.
	var sb strings.Builder
	sb.WriteString(`<!DOCTYPE html>
<html>
<head>
<title>Product Search Results</title>
<script>
window.addEventListener("DOMContentLoaded", function() {
    // Simple analytics: push search event to dataLayer.
    window.dataLayer = window.dataLayer || [];
    window.dataLayer.push({
        "event": "search",
        "keyword": `)
	sb.Write(keywordJSON)
	sb.WriteString(`
    });
});
</script>
</head>
<body>
<h2>Search Results: `)
	sb.WriteString(escapedKeyword)
	sb.WriteString(`</h2>
</body>
</html>`)

	// Write the response.
	w.Write([]byte(sb.String()))
}

func main() {
	// Register the product search handler under /search.
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server on port 8080.
	fmt.Println("Server listening on http://localhost:8080")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		fmt.Println("Server error:", err)
	}
}

