package main

import (
	"html/template"
	"log"
	"net/http"
	"strings"
)

type SearchData struct {
	Keyword string
	Results []string
}

var tmpl = template.Must(template.New("search").Parse(`<!DOCTYPE html>
<html>
<head>
	<title>Search Results: {{.Keyword}}</title>
</head>
<body>
	<h2>Search Results: {{.Keyword}}</h2>
	{{if .Results}}
	<ul>
		{{range .Results}}
		<li>{{.}}</li>
		{{end}}
	</ul>
	{{else}}
	<p>No results found.</p>
	{{end}}
</body>
</html>
`))

func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Only allow GET requests
	if r.Method != http.MethodGet {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	keyword := r.URL.Query().Get("keyword")
	if keyword == "" {
		keyword = "(none)"
	}

	// Server‑side analytics: log the search query
	log.Printf("Analytics: search keyword=%q from %s", keyword, r.RemoteAddr)

	// Dummy product catalog for demonstration
	allProducts := []string{
		"Apple iPhone 14",
		"Samsung Galaxy S22",
		"Google Pixel 7",
		"Apple MacBook Pro",
		"Dell XPS 13",
		"Sony WH‑1000XM5",
		"Apple Watch Series 8",
		"Bose QuietComfort 45",
		"Microsoft Surface Laptop 5",
		"Lenovo ThinkPad X1 Carbon",
	}

	// Filter products that contain the keyword (case‑insensitive)
	kwLower := strings.ToLower(keyword)
	var results []string
	for _, p := range allProducts {
		if strings.Contains(strings.ToLower(p), kwLower) {
			results = append(results, p)
		}
	}

	data := SearchData{
		Keyword: keyword,
		Results: results,
	}

	w.Header().Set("Content-Type", "text/html; charset=utf-8")
	if err := tmpl.Execute(w, data); err != nil {
		log.Printf("template error: %v", err)
	}
}

func main() {
	http.HandleFunc("/search", HandleProductSearch)

	log.Println("Server listening on :8080")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatal(err)
	}
}

