import (
	"fmt"
	"html/template"
	"log"
	"net/http"
)

// HandleProductSearch processes search requests and renders an HTML page
// displaying the search results for the given keyword. It also includes a
// simple client‑side script that reports the keyword to an analytics endpoint.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Only allow GET requests
	if r.Method != http.MethodGet {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	// Retrieve the keyword from the query string
	keyword := r.URL.Query().Get("keyword")
	if keyword == "" {
		keyword = "Unknown"
	}

	// Escape the keyword to prevent XSS when embedding in HTML
	escapedKeyword := template.HTMLEscapeString(keyword)

	// Set the response content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Render the page with the keyword and analytics script
	fmt.Fprintf(w, `<!DOCTYPE html>
<html>
<head>
    <meta charset="utf-8">
    <title>Search Results</title>
</head>
<body>
    <h2>Search Results: %s</h2>
    <script>
        // Simple client‑side analytics: send the keyword to our analytics endpoint
        (function() {
            var xhr = new XMLHttpRequest();
            var encodedKeyword = encodeURIComponent("%s");
            xhr.open("GET", "/analytics?keyword=" + encodedKeyword, true);
            xhr.send();
        })();
    </script>
</body>
</html>`, escapedKeyword, escapedKeyword)
}

// HandleAnalytics records search events for analytics purposes.
// In a production environment this would store the data in a database or forward
// it to an external analytics service.
func HandleAnalytics(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodGet {
		w.WriteHeader(http.StatusMethodNotAllowed)
		return
	}

	keyword := r.URL.Query().Get("keyword")
	log.Printf("Analytics: search keyword = %s", keyword)

	// Return a 204 No Content response
	w.WriteHeader(http.StatusNoContent)
}

func main() {
	// Register HTTP handlers
	http.HandleFunc("/search", HandleProductSearch)
	http.HandleFunc("/analytics", HandleAnalytics)

	// Start the HTTP server on port 8080
	log.Println("Server starting on :8080")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatalf("Server failed: %v", err)
	}
}

