package main

import (
	"html/template"
	"log"
	"net/http"
)

// HandleProductSearch handles product search requests.
// It expects a query parameter "keyword" and renders an HTML page
// showing the search results.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Only allow GET requests
	if r.Method != http.MethodGet {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	// Retrieve the keyword from query string; if absent an empty string is used
	keyword := r.URL.Query().Get("keyword")

	// HTML template with placeholders safely escaped
	const tmpl = `<!DOCTYPE html>
<html>
<head>
	<title>Product Search Results</title>
</head>
<body>
	<h2>Search Results: {{.Keyword}}</h2>
	<!-- Simple analytics: send the search term to an analytics endpoint -->
	<script>
		(function() {
			var keyword = {{.Keyword | js}};
			if (keyword) {
				fetch('/analytics', {
					method: 'POST',
					headers: {'Content-Type': 'application/json'},
					body: JSON.stringify({keyword: keyword})
				}).catch(function() {});
			}
		})();
	</script>
</body>
</html>`

	// Parse the template; using html/template ensures proper escaping
	t, err := template.New("search").Parse(tmpl)
	if err != nil {
		log.Printf("template parse error: %v", err)
		http.Error(w, "Internal server error", http.StatusInternalServerError)
		return
	}

	// Set content type before writing response
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Execute the template with the keyword
	if err := t.Execute(w, struct{ Keyword string }{Keyword: keyword}); err != nil {
		log.Printf("template execute error: %v", err)
	}
}

func main() {
	// Register the handler under /search
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server on port 8080
	log.Println("Starting server on :8080")
	log.Fatal(http.ListenAndServe(":8080", nil))
}

