</body>
</html>`, safeKeyword)
}

func main() {
	// Register the search handler on the /search endpoint.
	http.HandleFunc("/search", HandleProductSearch)

	// For convenience, also register the handler for the root URL.
	http.HandleFunc("/", HandleProductSearch)

	// Start the HTTP server on port 8080.
	log.Fatal(http.ListenAndServe(":8080", nil))
}

